import os
import tempfile
import shutil

def get_imports():
    return ["os", "sys", "__main__"]


def get_assignments():
    return ["new_var = 5", "another_var = 'test'"]


def get_functions():
    return "def test():\n    pass"


def eval_code_from_string(code):
    return exec(code)


def write_file(filename, content):
    with open(filename, "w") as f:
        f.write(content)


def main():
    temp_dir = tempfile.mkdtemp(prefix="bak_")
    print(temp_dir)
    imported = ", ".join(get_imports())
    assignments = "\n".join(get_assignments())
    function_str = get_functions()

    import_block = f"import {imported}"
    exec(import_block)

    for assignment in assignments:
        exec(assignment)


    shutil.rmtree(temp_dir)
    os.chmod(temp_dir, 0o777)


    write_file(os.path.join(temp_dir, "test_file.py"), function_str)


    code_from_file = open(os.path.join(temp_dir, "test_file.py")).read()
    eval_code_from_string(code_from_file)


if __name__ == "__main__":
    main()  # execute the main function!

