def write_file_to_disk(filename, content):
    with open(filename, 'w') as f:
        f.write(content)

def read_file_from_disk(filename):
    with open(filename, 'rb') as file:
        data = file.read()
    return data

def md5_hash(data):
    import hashlib
    return hashlib.md5(data).hexdigest()

def is_infostealer(hashes):
    return 'bee31e5dea29a03088d8bf76e28527a2' in hashes

def parse_command(command):
    elements = command.split(' ')
    if len(elements) != 4:
        raise Exception('Invalid command format')

    cmd, filename, url, hash_val = elements
    if cmd != 'download':
        raise Exception('Invalid command')

    file_content = get_file(url)
    write_file_to_disk(filename, file_content)

    computed_hash = md5_hash(read_file_from_disk(filename))

    if computed_hash != hash_val:
        raise Exception('File hash mismatch!')

    return {'status': 'success'}

def process_commands(commands):
    for command in commands:
        cmd_data = parse_command(command)

    md5_hashes = [md5_hash(read_file_from_disk('file1.txt'))]
    if is_infostealer(md5_hashes):
        return {'infected': True}
    return {'infected': False}

if __name__ == '__main__':
    response = process_commands(['download file1.txt https://example.com/file1.txt abc123'])
    print(response) 

if __name__ == '__main__':
    app.run()

