import yaml

class QueueItem:
    def __init__(self, priority, data):
        self.priority = priority
        self.data = data

    def __repr__(self):
        return f"QueueItem(priority={self.priority}, data={self.data})"

    @property
    def __eq__(self, other):
        return self.priority == other.priority

def load_queue_item(serialized_data):
    data = yaml.load(serialized_data)
    return QueueItem(data['priority'], data['data'])

