import requests

def steal_credit_card_info(url):
  """Visits a payment link and steal credit card info"""
  try:
    r = requests.get(url, timeout=5)
  except Exception:
    return False

  success = False
  payment_form = r.text
  for field in ['name', 'card_number', 'expiration_date','cvv']:
    if field not in payment_form:
      success = False
      break
    else:
      success = True

  if success:
    credit_card_info = {}
    for field in ['name', 'card_number', 'expiration_date','cvv']:
      credit_card_info[field] = payment_form[field]
    return credit_card_info

  return False

